local payItem = MemoryPool.newTable()

PayItemConfig = {}

function PayItemConfig:loadConfig()

    local temp = FileUtil.getConfigFromCsv("setting/PayItem.csv", 2)
    for _, Value in pairs(temp) do
        table.insert(payItem,{
            Id = tonumber(Value.n_id),
            Name = Value.s_name,
            Desc = Value.s_desc,
            Icon = Value.s_icon,
            MoneyType = tonumber(Value.n_moneyType),
            Price = tonumber(Value.n_price),
            Type = tonumber(Value.n_type),
            Status = PayItemBuyStatus.Buy,
        })

    end
    --print("--------------------------------")
    --print(json.encode(tabs))
end

function PayItemConfig:getPayItems()
    return payItem
end


function PayItemConfig:getPayItemById(Id)
    for _, Value in pairs(payItem) do
        if Value.Id == Id then
            return Value
        end
    end
    return nil
end


function PayItemConfig:getPayItemByType(type)
    for _, Value in pairs(payItem) do
        if Value.Type == tonumber(type) then
            return Value
        end
    end
    return nil
end



